+func TestGetSkillGroups_FallsBackToLegacyEndpointOnBlueprintNotFound(t *testing.T) {
+	var paths []string
+	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
+		if r.URL.Path == "/auth/access_token" {
+			json.NewEncoder(w).Encode(map[string]interface{}{"ok": true, "accessToken": "tok", "expiresIn": 3600})
+			return
+		}
+		paths = append(paths, r.URL.Path)
+		if r.URL.Path == "/blueprints/skill_group/entities/search" {
+			w.WriteHeader(http.StatusNotFound)
+			json.NewEncoder(w).Encode(map[string]interface{}{
+				"ok":      false,
+				"error":   "blueprint_not_found",
+				"message": "Blueprint skill_group does not exist",
+			})
+			return
+		}
+		json.NewEncoder(w).Encode(map[string]interface{}{
+			"ok":       true,
+			"entities": []map[string]interface{}{{"identifier": "legacy-group"}},
+		})
+	}))
+	defer server.Close()
+
+	client := NewClient(ClientOpts{ClientID: "id", ClientSecret: "secret", APIURL: server.URL, Timeout: 0})
+	entities, err := client.GetSkillGroups(context.Background())
+	if err != nil {
+		t.Fatalf("unexpected error: %v", err)
+	}
+	if len(entities) != 1 || entities[0]["identifier"] != "legacy-group" {
+		t.Fatalf("expected legacy group, got %+v", entities)
+	}
+	expected := []string{"/blueprints/skill_group/entities/search", "/blueprints/skill_group/entities"}
+	if len(paths) != len(expected) {
+		t.Fatalf("expected paths %v, got %v", expected, paths)
+	}
+}
+
+func TestGetSkillGroups_PropagatesNonBlueprintErrors(t *testing.T) {
+	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
+		if r.URL.Path == "/auth/access_token" {
+			json.NewEncoder(w).Encode(map[string]interface{}{"ok": true, "accessToken": "tok", "expiresIn": 3600})
+			return
+		}
+		w.WriteHeader(http.StatusInternalServerError)
+		json.NewEncoder(w).Encode(map[string]interface{}{"ok": false, "error": "internal_error"})
