154	// TestImportPages_PreservesTypeOnCreate verifies that `type` and navigation fields are
155	// sent to Port when creating a new page.
156	func TestImportPages_PreservesTypeOnCreate(t *testing.T) {
157		var receivedPage map[string]interface{}
158	
159		_, client := newTestServer(t, func(w http.ResponseWriter, r *http.Request) {
160			if authHandler(w, r) {
161				return
162			}
163			if r.Method == http.MethodPost && r.URL.Path == "/pages" {
164				json.NewDecoder(r.Body).Decode(&receivedPage)
165				json.NewEncoder(w).Encode(map[string]interface{}{"ok": true, "page": receivedPage})
166				return
167			}
168			http.NotFound(w, r)
169		})
170	
171		page := api.Page{
172			"identifier":          "aws_cost_overview",
173			"type":                "dashboard",
174			"parent":              "initiatives",
175			"sidebar":             "catalog",
176			"after":               "mastering_the_estate",
177			"requiredQueryParams": []interface{}{},
178			"title":               "AWS Cost Overview",
179			"widgets":             []interface{}{},
