181			"createdAt":           "2026-01-01",
182			"id":                  "internal-id",
183		}
184	
185		importer := NewImporter(client)
186		result := &Result{}
187		importer.importPages(context.Background(), []api.Page{page}, result)
188	
189		if result.PagesCreated != 1 {
190			t.Fatalf("expected 1 page created, got %d", result.PagesCreated)
191		}
192		if receivedPage["type"] != "dashboard" {
193			t.Errorf("expected type=dashboard to be sent on create, got %v", receivedPage["type"])
194		}
195		if receivedPage["parent"] != "initiatives" {
196			t.Errorf("expected parent=initiatives to be sent on create, got %v", receivedPage["parent"])
197		}
198		if receivedPage["sidebar"] != "catalog" {
199			t.Errorf("expected sidebar=catalog to be sent on create, got %v", receivedPage["sidebar"])
200		}
201		// System/audit fields must be stripped
